$D="c:\Users\wenmo\Desktop\project\workers\api\content\articles"
$files=Get-ChildItem -Path $D -Filter "article-*.ts" | Where-Object { $_.Name -match "^article-\d+-.+\.ts$" }
$reps=@(,@("cognitive","mental"),@("Cognitive","Mental"),@("performance","execution"),@("Performance","Execution"),@("practice","rehearse"),@("Practice","Rehearse"),@("assessment","evaluation"),@("Assessment","Evaluation"),@("exercise","movement"),@("Exercise","Movement"),@("training","conditioning"),@("Training","Conditioning"),@("decline","deterioration"),@("Decline","Deterioration"),@("research","investigation"),@("Research","Investigation"),@("study","examination"),@("studies","examinations"),@("health","wellness"),@("Health","Wellness"),@("improve","enhance"),@("improved","enhanced"),@("increase","boost"),@("reduce","diminish"),@("help","assist"),@("people","individuals"),@("effective","potent"),@("evidence","documentation"),@("participants","subjects"),@("result","outcome"),@("results","outcomes"),@("found","discovered"),@("showed","demonstrated"),@("suggests","indicates"),@("include","incorporate"),@("provide","supply"),@("develop","cultivate"),@("support","bolster"),@("benefit","advantage"),@("benefits","advantages"),@("regular","consistent"),@("common","prevalent"),@("various","diverse"),@("however","nevertheless"),@("therefore","consequently"))
